Decorators

Decorators are special declarations that can be attached to classes, methods, properties, and parameters to modify their behavior.

### Enabling Decorators

In `tsconfig.json`:

```json
{
  "compilerOptions": {
    "experimentalDecorators": true
  }
}
```

### Class Decorator

```typescript
function sealed(constructor: Function): void {
  Object.seal(constructor);
  Object.seal(constructor.prototype);
}

@sealed
class BugReport {
  title: string;

  constructor(title: string) {
    this.title = title;
  }
}
```

### Method Decorator

```typescript
function log(target: any, propertyKey: string, descriptor: PropertyDescriptor): void {
  const original = descriptor.value;

  descriptor.value = function (...args: any[]) {
    console.log(`Calling ${propertyKey} with:`, args);
    return original.apply(this, args);
  };
}

class Calculator {
  @log
  add(a: number, b: number): number {
    return a + b;
  }
}
```

### Property Decorator

```typescript
function defaultValue(value: string) {
  return (target: any, propertyKey: string): void => {
    target[propertyKey] = value;
  };
}

class User {
  @defaultValue("Guest")
  name: string;
}
```

### Decorator Factories

```typescript
function logWith(prefix: string) {
  return function (target: any, propertyKey: string, descriptor: PropertyDescriptor): void {
    const original = descriptor.value;
    descriptor.value = function (...args: any[]) {
      console.log(`${prefix}: ${propertyKey} called`);
      return original.apply(this, args);
    };
  };
}

class MyClass {
  @logWith("DEBUG")
  doSomething(): void {}
}
```

> **Key Point:** Decorators are a stage 3 proposal. Enable `experimentalDecorators` in tsconfig.

codeExample:
function readonly(target: any, propertyKey: string, descriptor: PropertyDescriptor): void {
  descriptor.writable = false;
}

function enumerable(value: boolean) {
  return (target: any, propertyKey: string, descriptor: PropertyDescriptor): void => {
    descriptor.enumerable = value;
  };
}

class Product {
  constructor(
    public name: string,
    private _price: number
  ) {}

  @readonly
  getId(): string {
    return `${this.name}_${Date.now()}`;
  }

  @enumerable(false)
  get price(): number {
    return this._price;
  }
}

const product = new Product("Laptop", 999);
